mapper.select:
select i.warehouse_id as warehouseId, coalesce(w.warehouse_name, concat('仓库#', i.warehouse_id)) as warehouseName, count(1) as inventoryRows, count(distinct i.product_id) as productCount, coalesce(sum(i.qty_piece), 0) as totalQtyPiece, coalesce(sum(i.locked_qty_piece), 0) as lockedQtyPiece, coalesce(sum(i.avail_qty_piece), 0) as availQtyPiece from ims_inventory i left join ims_warehouse w on w.id = i.warehouse_id
and i.enterprise_id = #{enterpriseId}
group by i.warehouse_id, w.warehouse_name order by totalQtyPiece desc limit 20

select i.product_id as productId, coalesce(p.product_name, concat('产品#', i.product_id)) as productName, i.warehouse_id as warehouseId, coalesce(w.warehouse_name, concat('仓库#', i.warehouse_id)) as warehouseName, i.location_id as locationId, i.qty_piece as qtyPiece, i.locked_qty_piece as lockedQtyPiece, i.avail_qty_piece as availQtyPiece from ims_inventory i left join ims_product p on p.id = i.product_id left join ims_warehouse w on w.id = i.warehouse_id
and i.enterprise_id = #{enterpriseId} and i.warehouse_id = #{warehouseId} and i.avail_qty_piece <= 0
order by i.avail_qty_piece asc, i.qty_piece asc limit #{limit}

select date(f.occur_time) as occurDate, coalesce(sum(case when f.`inout` = 'I' then f.qty_piece else 0 end), 0) as inboundQty, coalesce(sum(case when f.`inout` = 'O' then f.qty_piece else 0 end), 0) as outboundQty, coalesce(sum(case when f.`inout` = 'I' then coalesce(f.amount, 0) else 0 end), 0) as inboundAmount, coalesce(sum(case when f.`inout` = 'O' then coalesce(f.amount, 0) else 0 end), 0) as outboundAmount, count(1) as flowCount from ims_stock_flow f
and f.occur_time >= #{beginDate} and f.occur_time < date_add(#{endDate}, interval 1 day) and f.enterprise_id = #{enterpriseId} and f.warehouse_id = #{warehouseId}
group by date(f.occur_time) order by occurDate asc limit 90

select f.product_id as productId, coalesce(p.product_name, concat('产品#', f.product_id)) as productName, coalesce(sum(case when f.`inout` = 'I' then f.qty_piece else 0 end), 0) as inboundQty, coalesce(sum(case when f.`inout` = 'O' then f.qty_piece else 0 end), 0) as outboundQty, coalesce(sum(coalesce(f.amount, 0)), 0) as totalAmount, count(1) as flowCount from ims_stock_flow f left join ims_product p on p.id = f.product_id
and f.occur_time >= #{beginDate} and f.occur_time < date_add(#{endDate}, interval 1 day) and f.enterprise_id = #{enterpriseId} and f.warehouse_id = #{warehouseId}
group by f.product_id, p.product_name order by flowCount desc, totalAmount desc limit #{limit}

select
    count(1) as billCount,
    coalesce(sum(d.total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(d.total_amount), 0) as totalAmount,
    coalesce(avg(d.total_amount), 0) as avgBillAmount,
    sum(case when d.bill_status = '0' then 1 else 0 end) as draftCount,
    sum(case when d.bill_status = '1' then 1 else 0 end) as auditedCount,
    sum(case when d.bill_status = '2' then 1 else 0 end) as voidCount
from ims_damage d

    and d.bill_date >= #{beginDate}
    and d.bill_date <= #{endDate}
    and d.enterprise_id = #{enterpriseId}
    and d.warehouse_id = #{warehouseId}

select
    coalesce(nullif(trim(d.reason), ''), '未填写原因') as reason,
    count(1) as billCount,
    coalesce(sum(d.total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(d.total_amount), 0) as totalAmount
from ims_damage d

    and d.bill_date >= #{beginDate}
    and d.bill_date <= #{endDate}
    and d.enterprise_id = #{enterpriseId}
    and d.warehouse_id = #{warehouseId}

group by coalesce(nullif(trim(d.reason), ''), '未填写原因')
order by totalAmount desc
limit 20

select di.product_id as productId, coalesce(p.product_name, concat('产品#', di.product_id)) as productName, count(distinct d.id) as billCount, count(1) as lineCount, coalesce(sum(di.qty_piece), 0) as totalQtyPiece, coalesce(sum(di.amount), 0) as totalAmount from ims_damage_item di inner join ims_damage d on d.id = di.damage_id left join ims_product p on p.id = di.product_id
and d.bill_date >= #{beginDate} and d.bill_date <= #{endDate} and d.enterprise_id = #{enterpriseId} and d.warehouse_id = #{warehouseId}
group by di.product_id, p.product_name order by totalAmount desc, totalQtyPiece desc limit #{limit}

select coalesce(nullif(trim(use_dept), ''), '未填写部门') as useDept, count(1) as assetCount, coalesce(sum(original_value), 0) as originalValue, coalesce(sum(net_value), 0) as netValue, sum(case when status = '0' then 1 else 0 end) as activeCount, sum(case when status = '1' then 1 else 0 end) as disabledCount from ims_fixed_asset
and enterprise_id = #{enterpriseId}
group by coalesce(nullif(trim(use_dept), ''), '未填写部门') order by netValue desc limit 20

select id as assetId, asset_code as assetCode, asset_name as assetName, asset_category as assetCategory, use_dept as useDept, keeper, original_value as originalValue, net_value as netValue, status, purchase_date as purchaseDate, case when status = '1' then 'stopped_or_scrapped' when original_value > 0 and net_value / original_value <= 0.1 then 'low_net_value' when update_time is null and create_time < date_sub(now(), interval 365 day) then 'long_time_not_updated' when update_time < date_sub(now(), interval 365 day) then 'long_time_not_updated' else 'watch' end as riskType from ims_fixed_asset
and enterprise_id = #{enterpriseId} and ( status = '1' or (original_value > 0 and net_value / original_value <= 0.1) or (update_time is null and create_time < date_sub(now(), interval 365 day)) or update_time < date_sub(now(), interval 365 day) )
order by status desc, net_value asc, purchase_date asc limit #{limit}

select p.period_code as periodCode, count(distinct p.period_id) as periodCount, count(d.detail_id) as detailCount, count(distinct d.employee_id) as employeeCount, coalesce(sum(d.base_salary), 0) as baseSalary, coalesce(sum(d.commission), 0) as commission, coalesce(sum(d.allowance), 0) as allowance, coalesce(sum(d.bonus), 0) as bonus, coalesce(sum(d.deduction), 0) as deduction, coalesce(sum(d.net_pay), 0) as netPay, coalesce(avg(d.net_pay), 0) as avgNetPay from ims_payroll_period p inner join ims_payroll_detail d on d.period_id = p.period_id
and p.period_code = #{periodCode} and p.dept_id = #{deptId}
group by p.period_code order by p.period_code desc limit 1

select p.dept_id as deptId, coalesce(sd.dept_name, concat('部门#', p.dept_id)) as deptName, count(d.detail_id) as detailCount, count(distinct d.employee_id) as employeeCount, coalesce(sum(d.net_pay), 0) as netPay, coalesce(avg(d.net_pay), 0) as avgNetPay, coalesce(sum(d.deduction), 0) as deduction from ims_payroll_period p inner join ims_payroll_detail d on d.period_id = p.period_id left join sys_dept sd on sd.dept_id = p.dept_id
and p.period_code = #{periodCode}
group by p.dept_id, sd.dept_name order by netPay desc limit 20

select d.employee_id as employeeId, coalesce(e.employee_name, concat('员工#', d.employee_id)) as employeeName, coalesce(sd.dept_name, concat('部门#', p.dept_id)) as deptName, coalesce(sum(d.base_salary), 0) as baseSalary, coalesce(sum(d.commission), 0) as commission, coalesce(sum(d.bonus), 0) as bonus, coalesce(sum(d.deduction), 0) as deduction, coalesce(sum(d.net_pay), 0) as netPay from ims_payroll_period p inner join ims_payroll_detail d on d.period_id = p.period_id left join ims_employee e on e.id = d.employee_id left join sys_dept sd on sd.dept_id = p.dept_id
and p.period_code = #{periodCode}
group by d.employee_id, e.employee_name, sd.dept_name order by netPay desc limit #{limit}

select d.employee_id as employeeId, coalesce(e.employee_name, concat('员工#', d.employee_id)) as employeeName, coalesce(sd.dept_name, concat('部门#', p.dept_id)) as deptName, d.attendance_days as attendanceDays, d.base_salary as baseSalary, d.deduction as deduction, d.net_pay as netPay, case when d.attendance_days < 20 then 'low_attendance' when d.base_salary > 0 and d.deduction / d.base_salary >= 0.3 then 'high_deduction' when d.net_pay < 0 then 'negative_net_pay' else 'watch' end as abnormalType from ims_payroll_period p inner join ims_payroll_detail d on d.period_id = p.period_id left join ims_employee e on e.id = d.employee_id left join sys_dept sd on sd.dept_id = p.dept_id
and p.period_code = #{periodCode} and ( d.attendance_days < 20 or (d.base_salary > 0 and d.deduction / d.base_salary >= 0.3) or d.net_pay < 0 )
order by d.deduction desc, d.attendance_days asc limit #{limit}

select p.status, count(distinct p.period_id) as periodCount, count(d.detail_id) as detailCount, coalesce(sum(d.net_pay), 0) as netPay from ims_payroll_period p left join ims_payroll_detail d on d.period_id = p.period_id
and p.period_code = #{periodCode}
group by p.status order by p.status asc

select count(1) as warehouseCount, coalesce(sum(locationCount), 0) as locationCount, sum(case when warehouseStatus = '1' then 1 else 0 end) as disabledWarehouseCount, coalesce(sum(disabledLocationCount), 0) as disabledLocationCount, sum(case when locationCount = 0 then 1 else 0 end) as warehouseWithoutLocationCount, coalesce(avg(locationCount), 0) as avgLocationPerWarehouse from ( select w.id, w.status as warehouseStatus, count(l.id) as locationCount, sum(case when l.status = '1' then 1 else 0 end) as disabledLocationCount from ims_warehouse w left join ims_warehouse_location l on l.warehouse_id = w.id
and w.enterprise_id = #{enterpriseId} and w.id = #{warehouseId}
group by w.id, w.status ) warehouse_stat

select w.id as warehouseId, w.warehouse_code as warehouseCode, w.warehouse_name as warehouseName, w.status as warehouseStatus, count(l.id) as locationCount, sum(case when l.status = '1' then 1 else 0 end) as disabledLocationCount, case when count(l.id) = 0 then 'no_location' else 'ok' end as locationRisk from ims_warehouse w left join ims_warehouse_location l on l.warehouse_id = w.id
and w.enterprise_id = #{enterpriseId} and w.id = #{warehouseId}
group by w.id, w.warehouse_code, w.warehouse_name, w.status order by locationRisk desc, locationCount asc, w.id asc limit #{limit}

select
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(total_amount), 0) as totalAmount,
    coalesce(avg(total_amount), 0) as avgBillAmount,
    sum(case when bill_status = '0' then 1 else 0 end) as draftCount,
    sum(case when bill_status = '1' then 1 else 0 end) as auditedCount,
    sum(case when bill_status = '2' then 1 else 0 end) as voidCount
from ims_inbound

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

select
    i.supplier_id as supplierId,
    coalesce(s.supplier_name, concat('supplier#', i.supplier_id)) as supplierName,
    count(1) as billCount,
    coalesce(sum(i.total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(i.total_amount), 0) as totalAmount
from ims_inbound i
left join ims_supplier s on s.id = i.supplier_id

    and i.bill_date >= #{beginDate}
    and i.bill_date <= #{endDate}
    and i.enterprise_id = #{enterpriseId}
    and i.warehouse_id = #{warehouseId}

group by i.supplier_id, s.supplier_name
order by totalAmount desc, totalQtyPiece desc
limit #{limit}

select ii.product_id as productId, coalesce(p.product_name, concat('product#', ii.product_id)) as productName, count(distinct i.id) as billCount, count(1) as lineCount, coalesce(sum(ii.qty_piece), 0) as totalQtyPiece, coalesce(sum(ii.amount), 0) as totalAmount from ims_inbound_item ii inner join ims_inbound i on i.id = ii.inbound_id left join ims_product p on p.id = ii.product_id
and i.bill_date >= #{beginDate} and i.bill_date <= #{endDate} and i.enterprise_id = #{enterpriseId} and i.warehouse_id = #{warehouseId}
group by ii.product_id, p.product_name order by totalAmount desc, totalQtyPiece desc limit #{limit}

select
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(total_amount), 0) as totalAmount,
    coalesce(avg(total_amount), 0) as avgBillAmount,
    sum(case when bill_status = '0' then 1 else 0 end) as draftCount,
    sum(case when bill_status = '1' then 1 else 0 end) as auditedCount,
    sum(case when bill_status = '2' then 1 else 0 end) as voidCount
from ims_delivery

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

select
    d.customer_id as customerId,
    coalesce(c.customer_name, concat('customer#', d.customer_id)) as customerName,
    count(1) as billCount,
    coalesce(sum(d.total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(d.total_amount), 0) as totalAmount
from ims_delivery d
left join ims_customer c on c.id = d.customer_id

    and d.bill_date >= #{beginDate}
    and d.bill_date <= #{endDate}
    and d.enterprise_id = #{enterpriseId}
    and d.warehouse_id = #{warehouseId}

group by d.customer_id, c.customer_name
order by totalAmount desc, totalQtyPiece desc
limit #{limit}

select di.product_id as productId, coalesce(p.product_name, concat('product#', di.product_id)) as productName, count(distinct d.id) as billCount, count(1) as lineCount, coalesce(sum(di.qty_piece), 0) as totalQtyPiece, coalesce(sum(di.amount), 0) as totalAmount from ims_delivery_item di inner join ims_delivery d on d.id = di.delivery_id left join ims_product p on p.id = di.product_id
and d.bill_date >= #{beginDate} and d.bill_date <= #{endDate} and d.enterprise_id = #{enterpriseId} and d.warehouse_id = #{warehouseId}
group by di.product_id, p.product_name order by totalAmount desc, totalQtyPiece desc limit #{limit}

select
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(total_amount), 0) as totalAmount,
    coalesce(avg(total_amount), 0) as avgBillAmount,
    sum(case when bill_status = '0' then 1 else 0 end) as draftCount,
    sum(case when bill_status = '1' then 1 else 0 end) as auditedCount,
    sum(case when bill_status = '2' then 1 else 0 end) as voidCount
from ims_outbound

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

select
    out_type as outType,
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(total_amount), 0) as totalAmount
from ims_outbound

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

group by out_type
order by totalAmount desc, totalQtyPiece desc

select oi.product_id as productId, coalesce(p.product_name, concat('product#', oi.product_id)) as productName, count(distinct o.id) as billCount, count(1) as lineCount, coalesce(sum(oi.qty_piece), 0) as totalQtyPiece, coalesce(sum(oi.amount), 0) as totalAmount from ims_outbound_item oi inner join ims_outbound o on o.id = oi.outbound_id left join ims_product p on p.id = oi.product_id
and o.bill_date >= #{beginDate} and o.bill_date <= #{endDate} and o.enterprise_id = #{enterpriseId} and o.warehouse_id = #{warehouseId}
group by oi.product_id, p.product_name order by totalAmount desc, totalQtyPiece desc limit #{limit}

select
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(total_amount), 0) as totalAmount,
    coalesce(avg(total_amount), 0) as avgBillAmount,
    sum(case when bill_status = '0' then 1 else 0 end) as draftCount,
    sum(case when bill_status = '1' then 1 else 0 end) as auditedCount,
    sum(case when bill_status = '2' then 1 else 0 end) as voidCount
from ims_sale_return

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

select
    coalesce(nullif(trim(reason), ''), 'empty_reason') as reason,
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    coalesce(sum(total_amount), 0) as totalAmount
from ims_sale_return

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

group by coalesce(nullif(trim(reason), ''), 'empty_reason')
order by totalAmount desc, totalQtyPiece desc
limit 20

select ri.product_id as productId, coalesce(p.product_name, concat('product#', ri.product_id)) as productName, count(distinct r.id) as billCount, count(1) as lineCount, coalesce(sum(ri.qty_piece), 0) as totalQtyPiece, coalesce(sum(ri.amount), 0) as totalAmount from ims_sale_return_item ri inner join ims_sale_return r on r.id = ri.sale_return_id left join ims_product p on p.id = ri.product_id
and r.bill_date >= #{beginDate} and r.bill_date <= #{endDate} and r.enterprise_id = #{enterpriseId} and r.warehouse_id = #{warehouseId}
group by ri.product_id, p.product_name order by totalAmount desc, totalQtyPiece desc limit #{limit}

select
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    sum(case when bill_status = '0' then 1 else 0 end) as draftCount,
    sum(case when bill_status = '1' then 1 else 0 end) as auditedCount,
    sum(case when bill_status = '2' then 1 else 0 end) as voidCount,
    count(distinct customer_id) as customerCount
from ims_sample

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

select
    coalesce(nullif(trim(purpose), ''), 'empty_purpose') as purpose,
    count(1) as billCount,
    coalesce(sum(total_qty_piece), 0) as totalQtyPiece,
    count(distinct customer_id) as customerCount
from ims_sample

    and bill_date >= #{beginDate}
    and bill_date <= #{endDate}
    and enterprise_id = #{enterpriseId}
    and warehouse_id = #{warehouseId}

group by coalesce(nullif(trim(purpose), ''), 'empty_purpose')
order by totalQtyPiece desc, billCount desc
limit 20

select
    si.product_id as productId,
    coalesce(p.product_name, concat('product#', si.product_id)) as productName,
    count(distinct s.id) as billCount,
    count(1) as lineCount,
    coalesce(sum(si.qty_piece), 0) as totalQtyPiece
from ims_sample_item si
inner join ims_sample s on s.id = si.sample_id
left join ims_product p on p.id = si.product_id

    and s.bill_date >= #{beginDate}
    and s.bill_date <= #{endDate}
    and s.enterprise_id = #{enterpriseId}
    and s.warehouse_id = #{warehouseId}

group by si.product_id, p.product_name
order by totalQtyPiece desc, billCount desc
limit #{limit}
